123 <p>Het fragment [Vue2Fragment] beheert de weergave XML [vue2]. De code ervan is als volgt:</p> <pre><code>
package exemples.android.fragments;

import android.widget.TextView;
import exemples.android.R;
import exemples.android.architecture.AbstractFragment;
import exemples.android.architecture.Data;
import org.androidannotations.annotations.AfterViews;
import org.androidannotations.annotations.Click;
import org.androidannotations.annotations.EFragment;
import org.androidannotations.annotations.ViewById;

@EFragment(R.layout.vue2)
public class Vue2Fragment extends AbstractFragment {

    // de velden van het scherm
  @ViewById(R.id.textViewResultats)
  TextView txtResultats;

    @AfterViews
    void initFragment(){
        // geheugen
        afterViewsDone=true;
    }

  @Click(R.id.button_vue1)
    void navigateToView1() {
        // we navigeren naar weergave 1
        mainActivity.navigateToView(0);
    }

    @Override
    protected void updateFragment() {
        // de items uit de lijst die in weergave 1 zijn geselecteerd, worden weergegeven
        StringBuilder texte = new StringBuilder("Eléments sélectionnés [");
        for (Data data : mainActivity.getListe()) {
            if (data.isChecked()) {
                texte.append(String.format("(%s)", data.getTexte()));
            }
        }
        texte.append("]");
        txtResultats.setText(texte);
    }
}
</code></pre> <p>De belangrijke code staat in de methode [updateFragment] op regel 32:</p> <ul> <li>regel 34: de tekst die moet worden weergegeven in [TextView] nr. 2 wordt berekend; </li> <li>regels 35-39: de lijst met gegevens die door de [ListView] wordt weergegeven, wordt doorlopen. Deze lijst is opgeslagen in de activiteit; </li> <li>regel 36: als gegeven nr. i is aangevinkt, wordt de bijbehorende omschrijving toegevoegd aan een type [StringBuilder]; </li> <li>regel 41: de [TextView] geeft de berekende tekst weer; </li> </ul> <p></p>

Serveur <p>De klasse [MainActivity] is als volgt:</p> <pre><code>
package client.android.activity;

import android.util.Log;
import client.android.architecture.core.AbstractActivity;
import client.android.architecture.core.AbstractFragment;
import client.android.architecture.custom.IMainActivity;
import client.android.dao.entities.*;
import client.android.dao.service.Dao;
import client.android.dao.service.IDao;
import client.android.dao.service.Response;
import client.android.fragments.behavior.AccueilFragment_;
import client.android.fragments.behavior.AgendaFragment_;
import client.android.fragments.behavior.AjoutRvFragment_;
import client.android.fragments.behavior.ConfigFragment_;
import org.androidannotations.annotations.Bean;
import org.androidannotations.annotations.EActivity;
import rx.Observable;

import java.util.List;

@EActivity
public class MainActivity extends AbstractActivity {

  // laag [DAO]
  @Bean(Dao.class)
  protected IDao dao;

  // ouderklasse ---------------------------------------
  @Override
  protected void onCreateActivity() {
    // logboek
    if (IS_DEBUG_ENABLED) {
      Log.d(className, "onCreateActivity");
    }
  }

  @Override
  protected IDao getDao() {
    return dao;
  }

  @Override
  protected AbstractFragment[] getFragments() {
    AbstractFragment[] fragments= new AbstractFragment[]{new ConfigFragment_(), new AccueilFragment_(), new AgendaFragment_(), new AjoutRvFragment_()};
    return fragments;
  }

  @Override
  protected CharSequence getFragmentTitle(int position) {
    return null;
  }

  @Override
  protected void navigateOnTabSelected(int position) {

  }

  @Override
  protected int getFirstView() {
    return IMainActivity.VUE_CONFIG;
  }

  // interface IDao -----------------------------------------------------
...

  @Override
  public Observable&lt;Response&lt;List&lt;Client&gt;&gt;&gt; getAllClients() {
    return dao.getAllClients();
  }

  @Override
  public Observable&lt;Response&lt;List&lt;Medecin&gt;&gt;&gt; getAllMedecins() {
    return dao.getAllMedecins();
  }

  @Override
  public Observable&lt;Response&lt;List&lt;Creneau&gt;&gt;&gt; getAllCreneaux(long idMedecin) {
    return dao.getAllCreneaux(idMedecin);
  }

  @Override
  public Observable&lt;Response&lt;List&lt;Rv&gt;&gt;&gt; getRvMedecinJour(long idMedecin, String jour) {
    return dao.getRvMedecinJour(idMedecin, jour);
  }

  @Override
  public Observable&lt;Response&lt;Client&gt;&gt; getClientById(long id) {
    return dao.getClientById(id);
  }

  @Override
  public Observable&lt;Response&lt;Medecin&gt;&gt; getMedecinById(long id) {
    return dao.getMedecinById(id);
  }

  @Override
  public Observable&lt;Response&lt;Rv&gt;&gt; getRvById(long id) {
    return dao.getRvById(id);
  }

  @Override
  public Observable&lt;Response&lt;Creneau&gt;&gt; getCreneauById(long id) {
    return dao.getCreneauById(id);
  }

  @Override
  public Observable&lt;Response&lt;Rv&gt;&gt; ajouterRv(String jour, long idCreneau, long idClient) {
    return dao.ajouterRv(jour, idCreneau, idClient);
  }

  @Override
  public Observable&lt;Response&lt;Rv&gt;&gt; supprimerRv(long idRv) {
    return dao.supprimerRv(idRv);
  }

  @Override
  public Observable&lt;Response&lt;AgendaMedecinJour&gt;&gt; getAgendaMedecinJour(long idMedecin, String jour) {
    return dao.getAgendaMedecinJour(idMedecin, jour);
  }
}
</code></pre> <ul> <li>regels 21-66: deze regels zijn standaard opgenomen in het sjabloon [client-android-skel]; </li> <li>regels 66-119: implementatie van de interface [IDao]. Alle methoden delegeren het werk aan de laag [DAO] vanaf regel 26; </li> <li>regels 42-46: de methode [getFragments] retourneert de array met de vier fragmenten van de applicatie; </li> <li>regels 58-61: de configuratieweergave is de eerste weergave die wordt getoond wanneer de applicatie wordt gestart; </li> </ul> <p></p>
